using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using FL.NetModule;
using Vector3 = UnityEngine.Vector3;
public class Script
{
    public static object Main()
    {
        try
        {
            var player = PlayerManager.Controller;
            if (player == null) return "No player";
            var pos = player.GetTransform().position;
            var fwd = player.GetTransform().forward;
            var spawnPos = pos + fwd * 10f;
            var req = new OnTrafficVehicleReq();
            req.VehicleCfgId = 1;
            var loc = req._Location;
            loc.ToValid();
            loc.Data.X = spawnPos.x;
            loc.Data.Y = spawnPos.y;
            loc.Data.Z = spawnPos.z;
            var rot = req._Rotation;
            rot.ToValid();
            rot.Data.X = 0;
            rot.Data.Y = player.GetTransform().eulerAngles.y;
            rot.Data.Z = 0;
            NetCmd.OnTrafficVehicle(req, res => {
                if (res.IsOk())
                    Debug.Log("[Test] Traffic vehicle spawned, entityId=" + res.Data.VehicleEntity);
                else
                    Debug.LogError("[Test] Spawn failed");
            });
            return "Spawn requested at " + spawnPos;
        }
        catch (System.Exception ex) { return "Error: " + ex.Message + "\n" + ex.StackTrace; }
    }
}
